import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule, FormsModule, FormArray } from '@angular/forms';
import { forkJoin, switchMap, map } from 'rxjs';
import { LUCIDE_ICONS, LucideAngularModule } from 'lucide-angular';
import { AuthService } from '../../services/timbrature-auth.adapter';
import { ShiftRequestsService } from '../../services/shift-requests.service';
import { ShiftsService } from '../../services/shifts.service';
import { EmployeeShiftsService } from '../../services/employee-shifts.service';
import { UsersService } from '../../services/user.service';
import { EmployeeShift, Shift, ShiftRequest, ShiftRequestStatus, User } from '../../models';
import { CompanyService } from '../../services/company.service';

@Component({
  selector: 'app-shift-management',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, FormsModule, LucideAngularModule],
  templateUrl: './shift-management.component.html',
  styleUrls: ['./shift-management.component.css']
})
export class ShiftManagementComponent implements OnInit {

  private fb = inject(FormBuilder);
  private authService = inject(AuthService);
  private shiftRequestsService = inject(ShiftRequestsService);
  private shiftsService = inject(ShiftsService);
  private employeeShiftsService = inject(EmployeeShiftsService);
  private usersService = inject(UsersService);
  private companiesService = inject(CompanyService);

  currentUser: User;
  companyId: string;
  userRole: string;
  companyDetails: any; // dati azienda con opening_hours e closed_days

  // Programma di turni
  showWeeklyProgramForm = false;
  weeklyProgramForm!: FormGroup;  
  weeks: Array<{ weekNumber: number; start: string; end: string; shiftId: string | null }> = [];

  // Permessi utente
  userCanRequestShifts = false;
  userCanCreateCustomShifts = false;
  managerVisibilityMap: Record<string, any> = {};

  // Turni attuali arricchiti
  currentShifts: any[] = [];
  // Richieste
  shiftRequests: any[] = [];
  // Turni predefiniti
  availableShifts: Shift[] = [];
  // Dipendenti (per admin/manager)
  employees: User[] = [];

  // Stato UI
  loading = false;
  successMessage = '';
  errorMessage = '';

  // Gestione turni predefiniti
  showShiftsList = true;
  showAddShiftForm = false;
  newShiftForm!: FormGroup;
  editingShiftId: string | null = null;
  editingShiftData: Partial<Shift> = {};

  // Assegnazione turni
  showAssignForm = false;
  assignForm!: FormGroup;

  // Richiesta turno (employee)
  showRequestForm = false;
  requestForm!: FormGroup;
  requestType: 'predefined' | 'custom' = 'predefined';

  // Messaggi di warning
  timeWarning: string | null = null;

constructor() {
  this.currentUser = this.authService.currentUserSubject.value as any;
  this.companyId = this.authService.companyId!;
  this.userRole = this.currentUser?.role || '';
  this.userCanRequestShifts = (this.currentUser as any)?.can_request_shifts || false;
  this.userCanCreateCustomShifts = (this.currentUser as any)?.can_create_custom_shifts || false;
  this.weeklyProgramForm = this.fb.group({
    user_id: ['', Validators.required],
    period_start: ['', Validators.required],
    period_end: ['', Validators.required]
  });
}

  ngOnInit(): void {
    this.initShiftForm();
    this.initAssignForm();
    this.initRequestForm();
    this.loadCompanyDetails();
    this.loadData();

    this.weeklyProgramForm.get('period_start')?.valueChanges.subscribe(() => this.generateWeeks());
    this.weeklyProgramForm.get('period_end')?.valueChanges.subscribe(() => this.generateWeeks());

  }

  // Inizializzazioni form
  initShiftForm() {
    this.newShiftForm = this.fb.group({
      name: ['', Validators.required],
      start_time: ['', Validators.required],
      end_time: ['', Validators.required],
      mon: [false],
      tue: [false],
      wed: [false],
      thu: [false],
      fri: [false],
      sat: [false],
      sun: [false],
      color: ['#00530b'],
      days: this.fb.group({})  
    });
  }

  addDayControl(day: string) {
    const dayArray = this.fb.array([]);
    (this.newShiftForm.get('days') as FormGroup).addControl(day, dayArray);
    this.addTimeSlot(day); // aggiunge una fascia vuota di default
  }

  addTimeSlot(day: string) {
    const dayArray = (this.newShiftForm.get('days') as FormGroup).get(day) as FormArray;
    dayArray.push(this.fb.group({
      start: ['', Validators.required],
      end: ['', Validators.required]
    }));
  }

  removeTimeSlot(day: string, index: number) {
    const dayArray = (this.newShiftForm.get('days') as FormGroup).get(day) as FormArray;
    dayArray.removeAt(index);
  }

  initAssignForm() {
    this.assignForm = this.fb.group({
      user_id: ['', Validators.required],
      shift_id: ['', Validators.required],
      valid_from: ['', Validators.required],
      valid_to: [null]
    });
  }

  initRequestForm() {
    this.requestForm = this.fb.group({
      requestType: ['predefined'],
      shift_id: [null, Validators.required], // required per predefined
      custom_shift: this.fb.group({
        name: ['', Validators.required],
        start_time: ['', Validators.required],
        end_time: ['', Validators.required],
        mon: [false],
        tue: [false],
        wed: [false],
        thu: [false],
        fri: [false],
        sat: [false],
        sun: [false],
        color: ['#00530b']
      }),
      valid_from: ['', Validators.required],
      valid_to: [null],
      notes: ['']
    });

    // Cambia validators in base al tipo
    this.requestForm.get('requestType')?.valueChanges.subscribe(type => {
      const shiftIdControl = this.requestForm.get('shift_id');
      const customGroup = this.requestForm.get('custom_shift');
      if (type === 'predefined') {
        shiftIdControl?.setValidators([Validators.required]);
        customGroup?.disable();
      } else {
        shiftIdControl?.clearValidators();
        shiftIdControl?.setValue(null);
        customGroup?.enable();
      }
      shiftIdControl?.updateValueAndValidity();
    });
  }

  // Carica dettagli azienda
loadCompanyDetails() {
  this.companiesService.getById(this.companyId).subscribe(company => {
    this.companyDetails = company;
    this.managerVisibilityMap = (company as any).manager_visibility || {};
  });
}

  // Carica tutti i dati
  loadData() {
    this.loading = true;
    this.loadShifts();

    // Carica dipendenti se admin o manager
    if (this.userRole === 'admin' || this.userRole === 'manager') {
      this.usersService.getAll(this.companyId).subscribe(users => {
        this.employees = users;
      });
    }

    // Carica turni attuali
    if (this.userRole === 'admin') {
      forkJoin({
        empShifts: this.employeeShiftsService.getAll(this.companyId),
        users: this.usersService.getAll(this.companyId)
      }).subscribe({
        next: ({ empShifts, users }) => {
          this.employees = users;
          this.currentShifts = this.enrichShifts(empShifts);
          this.loading = false;
        },
        error: () => this.loading = false
      });
    } else if (this.userRole === 'manager') {
      forkJoin({
        empShifts: this.employeeShiftsService.getAll(this.companyId),
        users: this.usersService.getAll(this.companyId)
      }).pipe(
        map(({ empShifts, users }) => {
          this.employees = users;
          // Filtra per manager (funzione da implementare)
          return this.enrichShifts(empShifts);
        })
      ).subscribe({
        next: (shifts) => { this.currentShifts = shifts; this.loading = false; },
        error: () => this.loading = false
      });
    } else {
      this.employeeShiftsService.getByUser(this.currentUser.id).subscribe({
        next: (empShifts) => {
          this.currentShifts = this.enrichShifts(empShifts);
          this.loading = false;
        },
        error: () => this.loading = false
      });
    }

    this.loadShiftRequests();
  }

  loadShifts() {
    this.shiftsService.getAll(this.companyId).subscribe(shifts => {
      this.availableShifts = shifts;
    });
  }

  enrichShifts(empShifts: EmployeeShift[]): any[] {
    return empShifts.map(es => {
      const shift = this.availableShifts.find(s => s.id === es.shift_id);
      const user = this.employees.find(u => u.id === es.user_id);
      return { ...es, shiftDetails: shift, user_name: user ? `${user.first_name} ${user.last_name}` : 'N/A' };
    });
  }

  loadShiftRequests() {
    if (this.userRole === 'admin') {
      this.shiftRequestsService.getAll(this.companyId, { orderBy: 'requested_at', ascending: false })
        .subscribe(requests => this.shiftRequests = this.enrichRequests(requests));
    } else if (this.userRole === 'manager') {
      this.shiftRequestsService.getAll(this.companyId)
        .subscribe(requests => {
          // Filtra per manager (da implementare)
          this.shiftRequests = this.enrichRequests(requests);
        });
    } else {
      this.shiftRequestsService.getAll(this.companyId)
        .subscribe(requests => {
          const filtered = requests.filter(r => r.user_id === this.currentUser.id);
          this.shiftRequests = this.enrichRequests(filtered);
        });
    }
  }

  enrichRequests(requests: ShiftRequest[]): any[] {
    return requests.map(req => {
      const user = this.employees.find(u => u.id === req.user_id);
      return { ...req, user_name: user ? `${user.first_name} ${user.last_name}` : 'N/A' };
    });
  }

  // Helper per permessi manager (da completare con logica reale)
canManageShifts(): boolean {
  if (this.userRole === 'admin') return true;
  if (this.userRole === 'manager') {
    const perms = this.managerVisibilityMap[this.currentUser.id] || {};
    return !!perms.can_manage_shifts;
  }
  return false;
}

  // Controlli su orari e giorni chiusi
  isDayClosed(day: string): boolean {
    if (!this.companyDetails?.opening_hours) {
      return false;
    }
    const dayData = this.companyDetails.opening_hours[day];
    return dayData?.closed === true;
  }

  isDateClosed(date: string): boolean {
    if (!this.companyDetails?.closed_days) return false;
    return this.companyDetails.closed_days.some((cd: any) => {
      if (cd.type === 'single') {
        return cd.start === date;
      } else if (cd.type === 'range') {
        return date >= cd.start && date <= cd.end;
      }
      return false;
    });
  }

  isTimeOutsideWorkHours(day: string, time: string): boolean {
    if (!this.companyDetails?.opening_hours) return false;
    const dayData = this.companyDetails.opening_hours[day];
    if (!dayData || dayData.closed) return true;
    const open = dayData.open;
    const close = dayData.close;
    if (!open || !close) return true;
    return time < open || time > close;
  }


  // Metodi CRUD turni predefiniti
  createShift() {
    if (this.newShiftForm.invalid) return;
    const shiftData = {
      ...this.newShiftForm.value,
      company_id: this.companyId
    };
    this.shiftsService.create(shiftData).subscribe({
      next: () => {
        this.successMessage = 'Turno creato';
        this.showAddShiftForm = false;
        this.newShiftForm.reset({
          mon: false, tue: false, wed: false, thu: false, fri: false, sat: false, sun: false,
          color: '#00530b'
        });
        this.loadShifts();
      },
      error: err => this.errorMessage = 'Errore creazione turno'
    });
  }

  beginEditShift(shift: Shift) {
    this.editingShiftId = shift.id;
    this.editingShiftData = { ...shift };
  }

  saveEditShift() {
    if (!this.editingShiftId) return;
    this.shiftsService.update(this.editingShiftId, this.editingShiftData).subscribe({
      next: () => {
        this.successMessage = 'Turno aggiornato';
        this.editingShiftId = null;
        this.editingShiftData = {};
        this.loadShifts();
      },
      error: err => this.errorMessage = 'Errore aggiornamento'
    });
  }

  cancelEditShift() {
    this.editingShiftId = null;
    this.editingShiftData = {};
  }

  deleteShift(shiftId: string) {
    if (confirm('Sei sicuro di voler eliminare questo turno?')) {
      this.shiftsService.delete(shiftId, this.companyId).subscribe({
        next: () => {
          this.successMessage = 'Turno eliminato';
          this.loadShifts();
        },
        error: err => this.errorMessage = 'Errore eliminazione'
      });
    }
  }

  // Assegnazione turno
  assignShift() {
    if (this.assignForm.invalid) return;
    const assignData: Partial<EmployeeShift> = {
      company_id: this.companyId,
      user_id: this.assignForm.value.user_id,
      shift_id: this.assignForm.value.shift_id,
      valid_from: this.assignForm.value.valid_from,
      valid_to: this.assignForm.value.valid_to || null
    };
    this.employeeShiftsService.create(assignData).subscribe({
      next: () => {
        this.successMessage = 'Turno assegnato';
        this.showAssignForm = false;
        this.assignForm.reset();
        this.loadData();
      },
      error: err => this.errorMessage = 'Errore assegnazione'
    });
  }

  // Richiesta turno (employee)
  submitRequest() {
    if (this.requestForm.invalid) return;
    const formValue = this.requestForm.value;
    const request: Partial<ShiftRequest> = {
      company_id: this.companyId,
      user_id: this.currentUser.id,
      valid_from: formValue.valid_from,
      valid_to: formValue.valid_to || null,
      notes: formValue.notes,
      status: 'pending' as ShiftRequestStatus
    };
    if (formValue.requestType === 'predefined') {
      request.shift_id = formValue.shift_id;
      request.custom_shift = null;
    } else {
      request.shift_id = null;
      request.custom_shift = formValue.custom_shift;
    }
    this.shiftRequestsService.create(request).subscribe({
      next: () => {
        this.successMessage = 'Richiesta inviata con successo';
        this.showRequestForm = false;
        this.requestForm.reset({ requestType: 'predefined' });
        this.loadShiftRequests();
      },
      error: (err) => this.errorMessage = 'Errore durante l\'invio'
    });
  }

  // Gestione richieste (admin/manager)
  approveRequest(requestId: string) {
    const request = this.shiftRequests.find(r => r.id === requestId);
    if (!request) return;

    if (!request.shift_id && !request.custom_shift) {
      this.errorMessage = 'La richiesta non ha un turno valido';
      return;
    }

    this.shiftRequestsService.update(requestId, {
      status: 'approved',
      reviewed_by: this.currentUser.id,
      reviewed_at: new Date().toISOString()
    }).pipe(
      switchMap(updated => {
        if (updated.shift_id) {
          // Turno predefinito
          const employeeShift: Partial<EmployeeShift> = {
            company_id: this.companyId,
            user_id: updated.user_id,
            shift_id: updated.shift_id,
            valid_from: updated.valid_from,
            valid_to: updated.valid_to
          };
          return this.employeeShiftsService.create(employeeShift);
        } else {
          // Turno personalizzato: bisognerebbe creare un nuovo turno in shifts? O gestire custom_shift direttamente?
          // Per ora creiamo un turno predefinito basato su custom_shift
          const custom = updated.custom_shift;
          const newShift: Partial<Shift> = {
            company_id: this.companyId,
            name: custom.name,
            start_time: custom.start_time,
            end_time: custom.end_time,
            mon: custom.mon,
            tue: custom.tue,
            wed: custom.wed,
            thu: custom.thu,
            fri: custom.fri,
            sat: custom.sat,
            sun: custom.sun,
            color: custom.color
          };
          return this.shiftsService.create(newShift).pipe(
            switchMap(createdShift => {
              const employeeShift: Partial<EmployeeShift> = {
                company_id: this.companyId,
                user_id: updated.user_id,
                shift_id: createdShift.id,
                valid_from: updated.valid_from,
                valid_to: updated.valid_to
              };
              return this.employeeShiftsService.create(employeeShift);
            })
          );
        }
      })
    ).subscribe({
      next: () => {
        this.successMessage = 'Richiesta approvata e turno assegnato';
        this.loadShiftRequests();
        this.loadData();
      },
      error: () => this.errorMessage = 'Errore nell\'approvazione'
    });
  }

  rejectRequest(requestId: string) {
    this.shiftRequestsService.update(requestId, {
      status: 'rejected',
      reviewed_by: this.currentUser.id,
      reviewed_at: new Date().toISOString()
    }).subscribe({
      next: () => {
        this.successMessage = 'Richiesta rifiutata';
        this.loadShiftRequests();
      },
      error: () => this.errorMessage = 'Errore'
    });
  }

  cancelRequest(requestId: string) {
    this.shiftRequestsService.update(requestId, { status: 'cancelled' }).subscribe({
      next: () => {
        this.successMessage = 'Richiesta cancellata';
        this.loadShiftRequests();
      },
      error: () => this.errorMessage = 'Errore'
    });
  }

  getShiftName(shiftId: string | null | undefined): string {
    if (!shiftId) return 'Personalizzato';
    const shift = this.availableShifts.find(s => s.id === shiftId);
    return shift ? shift.name : 'Sconosciuto';
  }

  get expiringShiftsCount(): number {
    const today = new Date();
    const nextWeek = new Date(today);
    nextWeek.setDate(today.getDate() + 7);
    return this.currentShifts.filter(cs => 
      cs.valid_to && new Date(cs.valid_to) <= nextWeek && new Date(cs.valid_to) >= today
    ).length;
  }


generateWeeks() {
  const start = this.weeklyProgramForm.get('period_start')?.value;
  const end = this.weeklyProgramForm.get('period_end')?.value;
  if (!start || !end) {
    this.weeks = [];
    return;
  }

  const startDate = new Date(start);
  const endDate = new Date(end);
  this.weeks = [];

  // Trova il primo lunedì (o lunedì) - personalizzabile
  let current = new Date(startDate);
  // Sposta current al lunedì della settimana corrente (se non lo è già)
  const day = current.getDay(); // 0 = domenica, 1 = lunedì, ..., 6 = sabato
  const diff = (day === 0 ? 6 : day - 1); // giorni da sottrarre per arrivare a lunedì
  current.setDate(current.getDate() - diff);

  let weekNumber = 1;
  while (current <= endDate) {
    const weekStart = new Date(current);
    const weekEnd = new Date(current);
    weekEnd.setDate(weekEnd.getDate() + 6); // domenica
    if (weekEnd > endDate) {
      weekEnd.setTime(endDate.getTime()); // ultima settimana accorciata
    }

    this.weeks.push({
      weekNumber: weekNumber++,
      start: this.formatDate(weekStart),
      end: this.formatDate(weekEnd),
      shiftId: null
    });

    // Vai alla prossima settimana
    current.setDate(current.getDate() + 7);
  }
}

formatDate(date: Date): string {
  return date.toISOString().split('T')[0];
}

assignWeeklyShifts() {
  if (this.weeklyProgramForm.invalid || this.weeks.some(w => !w.shiftId)) {
    this.errorMessage = 'Completa tutti i campi e seleziona un turno per ogni settimana';
    return;
  }

  const userId = this.weeklyProgramForm.value.user_id;
  const assignments = this.weeks.map(week => ({
    company_id: this.companyId,
    user_id: userId,
    shift_id: week.shiftId as string,  // cast sicuro perché abbiamo controllato
    valid_from: week.start,
    valid_to: week.end
  }));

  this.loading = true;
  forkJoin(assignments.map(a => this.employeeShiftsService.create(a))).subscribe({
    next: () => {
      this.successMessage = 'Programma settimanale creato con successo';
      this.showWeeklyProgramForm = false;
      this.loadData();
    },
    error: (err) => {
      this.errorMessage = 'Errore nella creazione del programma';
      this.loading = false;
    }
  });
}

get isWeeklyProgramCompleto(): boolean {
  return this.weeklyProgramForm.valid && this.weeks.every(w => w.shiftId !== null);
}

}
