import { Injectable } from '@angular/core';
import { BaseService } from './base.service';
import { EmployeeShift } from '../models';
import { from, map } from 'rxjs';

@Injectable({ providedIn: 'root' })
export class EmployeeShiftsService extends BaseService<EmployeeShift> {
  protected override tableName = 'employee_shifts';

  // Metodo per ottenere i turni di un utente specifico
  getByUser(userId: string) {
    return from(
      this.supabase
        .from(this.tableName)
        .select('*')
        .eq('user_id', userId)
    ).pipe(map(result => result.data as EmployeeShift[]));
  }
}
